type node struct {
	key   int
	left  *node
	right *node
}

func insertNode(root *node, key int) *node {
	if root == nil {
		return &node{key: key}
	}
	if key <= root.key {
		root.left = insertNode(root.left, key)
	} else {
		root.right = insertNode(root.right, key)
	}
	return root
}

func inorder(root *node, result *[]int) {
	if root == nil {
		return
	}
	inorder(root.left, result)
	*result = append(*result, root.key)
	inorder(root.right, result)
}

// BstInorder inserts all elements into a BST and returns the inorder traversal.
func BstInorder(arr []int) []int {
	var root *node
	for _, key := range arr {
		root = insertNode(root, key)
	}

	result := make([]int, 0, len(arr))
	inorder(root, &result)
	return result
}

import java.util.ArrayList;
import java.util.List;

public class BinarySearchTree {

    private static class Node {
        int key;
        Node left, right;

        Node(int key) {
            this.key = key;
        }
    }

    private static Node insert(Node root, int key) {
        if (root == null) {
            return new Node(key);
        }
        if (key <= root.key) {
            root.left = insert(root.left, key);
        } else {
            root.right = insert(root.right, key);
        }
        return root;
    }

    private static void inorder(Node root, List<Integer> result) {
        if (root == null) {
            return;
        }
        inorder(root.left, result);
        result.add(root.key);
        inorder(root.right, result);
    }

    public static int[] bstInorder(int[] arr) {
        Node root = null;
        for (int key : arr) {
            root = insert(root, key);
        }

        List<Integer> result = new ArrayList<>();
        inorder(root, result);

        return result.stream().mapToInt(Integer::intValue).toArray();
    }
}

