            root.left = insert(root.left, key)
        } else {
            root.right = insert(root.right, key)
        }
        return root
    }

    fun inorder(root: BSTNode?, result: MutableList<Int>) {
        if (root == null) return
        inorder(root.left, result)
        result.add(root.key)
