func bstInorder(_ arr: [Int]) -> [Int] {
    func insert(_ root: BSTNode?, _ key: Int) -> BSTNode {
        guard let root = root else {
            return BSTNode(key)
        }
        if key <= root.key {
            root.left = insert(root.left, key)
        } else {
            root.right = insert(root.right, key)
        }
        return root
    }

    func inorder(_ root: BSTNode?, _ result: inout [Int]) {
        guard let root = root else { return }
        inorder(root.left, &result)
        result.append(root.key)
        inorder(root.right, &result)
    }

    var root: BSTNode? = nil
    for key in arr {
        root = insert(root, key)
    }

    var result: [Int] = []
    inorder(root, &result)
    return result
}

class BSTNode {
    key: number;
    left: BSTNode | null = null;
    right: BSTNode | null = null;

    constructor(key: number) {
        this.key = key;
    }
}

function insert(root: BSTNode | null, key: number): BSTNode {
    if (root === null) {
        return new BSTNode(key);
    }
    if (key <= root.key) {
        root.left = insert(root.left, key);
    } else {
        root.right = insert(root.right, key);
    }
    return root;
}

function inorder(root: BSTNode | null, result: number[]): void {
    if (root === null) {
        return;
    }
    inorder(root.left, result);
    result.push(root.key);
    inorder(root.right, result);
}

export function bstInorder(arr: number[]): number[] {
    let root: BSTNode | null = null;
    for (const key of arr) {
        root = insert(root, key);
    }

    const result: number[] = [];
    inorder(root, result);
    return result;
}
